import{_ as p,o as a,c as r,a9 as t}from"./chunks/framework.D4xYp1Zt.js";const n="/images/why-generation-y-yuppies-are-unhappy/Lucy.png",o="/images/why-generation-y-yuppies-are-unhappy/H-253DR-E.png",s="/images/why-generation-y-yuppies-are-unhappy/Lucy-s-Parents.png",i="/images/why-generation-y-yuppies-are-unhappy/Lucy-s-Grandparents.png",y="/images/why-generation-y-yuppies-are-unhappy/green-grass.png",h="/images/why-generation-y-yuppies-are-unhappy/parent-expectation.png",g="/images/why-generation-y-yuppies-are-unhappy/parent-reality.png",m="/images/why-generation-y-yuppies-are-unhappy/flowers.png",u="/images/why-generation-y-yuppies-are-unhappy/President.png",c="/images/why-generation-y-yuppies-are-unhappy/a-secure-career.png",l="/images/why-generation-y-yuppies-are-unhappy/a-fulfilling-career.png",_="/images/why-generation-y-yuppies-are-unhappy/you-2527re-special.png",w="/images/why-generation-y-yuppies-are-unhappy/unicorn.png",Y="/images/why-generation-y-yuppies-are-unhappy/GYPSY-expectation.png",b="/images/why-generation-y-yuppies-are-unhappy/looking-up.png",f="/images/why-generation-y-yuppies-are-unhappy/taunted.png",P="/images/why-generation-y-yuppies-are-unhappy/pinit_fg_en_rect_gray_20.png",A=JSON.parse('{"title":"Why Generation Y Yuppies Are Unhappy","description":"","frontmatter":{"title":"Why Generation Y Yuppies Are Unhappy","titleZh":"为什么 Y 世代雅痞不快乐","date":"2013-09-09T00:00:00.000Z","originalUrl":"https://waitbutwhy.com/2013/09/why-generation-y-yuppies-are-unhappy.html","slug":"why-generation-y-yuppies-are-unhappy"},"headers":[],"relativePath":"posts/why-generation-y-yuppies-are-unhappy.md","filePath":"posts/why-generation-y-yuppies-are-unhappy.md","lastUpdated":1782886257000}'),d={name:"posts/why-generation-y-yuppies-are-unhappy.md"};function G(k,e,S,L,q,x){return a(),r("div",null,[...e[0]||(e[0]=[t('<h1 id="为什么-y-世代雅痞不快乐-·-why-generation-y-yuppies-are-unhappy" tabindex="-1">为什么 Y 世代雅痞不快乐 · Why Generation Y Yuppies Are Unhappy <a class="header-anchor" href="#为什么-y-世代雅痞不快乐-·-why-generation-y-yuppies-are-unhappy" aria-label="Permalink to &quot;为什么 Y 世代雅痞不快乐 · Why Generation Y Yuppies Are Unhappy&quot;">​</a></h1><blockquote><p>原文:<a href="https://waitbutwhy.com/2013/09/why-generation-y-yuppies-are-unhappy.html" target="_blank" rel="noreferrer">https://waitbutwhy.com/2013/09/why-generation-y-yuppies-are-unhappy.html</a> · 2013-09-09</p></blockquote><p>来跟 Lucy 打个招呼。</p><p><img src="'+n+'" alt=""></p><p>Lucy 属于 Y 世代 (Generation Y),也就是 1970 年代末到 1990 年代中期出生的这一代。她同时也属于占据 Y 世代很大一部分人口的雅痞 (yuppie) 文化。</p><p>对于 Y 世代年龄段里的雅痞,我有个专门的称呼——我叫他们「Y 世代主角与特殊雅痞」(Gen Y Protagonists &amp; Special Yuppies),简称 GYPSY。GYPSY 是一种独特品牌的雅痞,他们觉得自己是一个非常特别的故事里的主角。</p><p>所以 Lucy 正在享受她的 GYPSY 人生,她对身为 Lucy 这件事非常满意。只有一个小问题:</p><p>Lucy 有点不开心。</p><p>要弄清楚原因,我们首先得定义一下,是什么让一个人快乐或不快乐。这归结为一个很简单的公式:</p><p><img src="'+o+'" alt=""></p><p>这挺直白的——当一个人的生活现实比他们预期的要好时,他们就开心。当现实比预期的差时,他们就不开心。</p><p>为了提供一些背景,我们先把 Lucy 的父母拉进讨论:</p><p><img src="'+s+'" alt=""></p><p>Lucy 的父母出生于 50 年代——他们是婴儿潮一代 (Baby Boomers)。他们是被 Lucy 的祖父母养大的,那一代人属于所谓的「最伟大的一代」(Greatest Generation) 或称 G.I. 世代,他们在大萧条中长大,打过二战,绝对不是什么 GYPSY。</p><p><img src="'+i+'" alt=""></p><p>Lucy 那些经历过大萧条的祖父母极度痴迷于经济上的安全感,他们把 Lucy 的父母培养得追求务实、稳定的职业。他们希望 Lucy 父母的职业能比自己的更绿油油一点,于是 Lucy 的父母从小就被教导要为自己规划一份繁荣而稳定的事业。大概像这样:</p><p><img src="'+y+'" alt=""></p><p>他们被教导:没有任何东西能阻止他们抵达那片绿油油的职业草坪,但他们得投入好多年的辛勤工作才能到达。</p><p><img src="'+h+'" alt=""></p><p>从令人无法忍受的嬉皮士阶段毕业之后,Lucy 的父母开启了自己的事业。随着 70 年代、80 年代、90 年代滚滚而过,世界进入了一个空前经济繁荣的时代。Lucy 的父母做得比他们预期的还要好。这让他们感到心满意足、充满乐观。</p><p><img src="'+g+'" alt=""></p><p>因为拥有比自己父母那一代更顺遂、更积极的人生体验,Lucy 的父母在养育 Lucy 时给了她满满的乐观和「一切皆有可能」的感觉。而且这不只是他们家。全国乃至全世界的婴儿潮父母都告诉自己的 Y 世代孩子:你想成为什么就能成为什么,把「特别的主角」这种身份认同深深植入了他们的心灵深处。</p><p>这让 GYPSY 们对自己的职业前景抱有极大的希望,以至于父母那一代人所追求的「一片绿油油的、稳稳当当的富足草坪」在他们眼里根本不够看。配得上 GYPSY 的草坪,得有<em>花</em>才行。</p><p><img src="'+m+'" alt=""></p><p>这就引出了关于 GYPSY 的第一个事实:</p><h2 id="gypsy-野心爆棚" tabindex="-1"><strong>GYPSY 野心爆棚</strong> <a class="header-anchor" href="#gypsy-野心爆棚" aria-label="Permalink to &quot;**GYPSY 野心爆棚**&quot;">​</a></h2><p><img src="'+u+'" alt=""></p><p>GYPSY 想从职业里得到的,远远不止一片富足与安全感的绿草坪。事实是,一片绿草坪对 GYPSY 来说不够特别、不够独一无二。婴儿潮一代想过的是「美国梦」,而 GYPSY 想过的是「专属于我自己的梦」。</p><p>Cal Newport <a href="https://blogs.hbr.org/cs/2012/09/solving_gen_ys_passion_problem.html" target="_blank" rel="noreferrer">指出</a>,「追随你的热情」这个口号是最近 20 年才火起来的——这是根据 <a href="https://books.google.com/ngrams/graph?content=follow+your+passion&amp;year_start=1985&amp;year_end=2008&amp;corpus=0&amp;smoothing=3&amp;share=" target="_blank" rel="noreferrer">Google 的 Ngram viewer</a> 得出的结论,这个工具可以显示某个词组在英文出版物中在任意<a href="https://waitbutwhy.com/2013/08/putting-time-in-perspective.html" target="_blank" rel="noreferrer">时间段</a>里的出现频率。同一个 Ngram viewer 还显示,「一份稳定的职业」这个短语<a href="https://books.google.com/ngrams/graph?content=a+secure+career&amp;year_start=1985&amp;year_end=2008&amp;corpus=0&amp;smoothing=3&amp;share=" target="_blank" rel="noreferrer">已经过时</a>,而「一份有成就感的职业」这个短语<a href="https://books.google.com/ngrams/graph?content=a+fulfilling+career&amp;year_start=1985&amp;year_end=2008&amp;corpus=0&amp;smoothing=3&amp;share=" target="_blank" rel="noreferrer">则变得炙手可热</a>。</p><p><img src="'+c+'" alt=""></p><p><img src="'+l+'" alt=""></p><p>先说清楚,GYPSY 跟他们父母一样也想要经济上的富足——他们只是<em>同时</em>还想要一份有成就感的事业,而这恰恰是他们父母那代人没那么在意的东西。</p><p>但另一件事也在发生。整个 Y 世代的职业目标变得更加具体、更加雄心勃勃的同时,Lucy 在整个童年里还被灌输了另一条讯息:</p><p><img src="'+_+'" alt=""></p><p>现在或许是引出关于 GYPSY 的第二个事实的好时机:</p><h2 id="gypsy-活在幻觉里" tabindex="-1"><strong>GYPSY 活在幻觉里</strong> <a class="header-anchor" href="#gypsy-活在幻觉里" aria-label="Permalink to &quot;**GYPSY 活在幻觉里**&quot;">​</a></h2><p>「当然啦,」Lucy 被这样教育,「每个人都会去找一份有成就感的职业,但<em>我可是格外出众的</em>,所以我的事业和人生道路会在人群中脱颖而出。」于是,在整个世代都怀揣着「开满鲜花的职业草坪」这个大胆目标的基础上,<em>每一个 GYPSY 个体</em>都觉得<em>他或她</em>注定要拥有更好的东西——</p><p><em>一只闪闪发光的独角兽,站在鲜花盛开的草坪上。</em></p><p><img src="'+w+'" alt=""></p><p>那这为啥是幻觉呢?因为所有 GYPSY 都是这么想的,而这本身就违背了「特别」的定义:</p><p><strong>spe-cial| ‘speSHel |</strong><em><strong>形容词</strong></em><strong>比通常情况更好、更了不起,或以其他方式与众不同。</strong></p><p>按照这个定义,大多数人是不特别的——否则「特别」这个词就没意义了。</p><p>甚至现在,正在读这篇文章的 GYPSY 们都在想:「说得好……但我确实<em>是</em>那少数几个特别的人之一」——这就是问题所在。</p><p>一旦 GYPSY 进入就业市场,第二种幻觉就登场了。露西 (Lucy) 的父母期待的是,多年的辛苦工作最终会带来一份好职业;而露西则认为,像她这么出众的人,拥有一份好职业是理所当然的,不过是时间问题以及选择走哪条路罢了。她进入职场前的期望大致长这样:</p><p><img src="'+Y+'" alt=""></p><p>不幸的是,这个世界有个搞笑的地方——它其实没那么好混;而职业生涯的怪异之处在于,它其实相当难搞。伟大的职业需要多年的血、汗和泪水才能建立起来——就算是那些没有鲜花没有独角兽的职业也一样——即使是最成功的人,在他们二十出头或二十五六岁时也很少能做出什么了不起的事。</p><p>但 GYPSY 们可不会就这么接受这个现实。</p><p>新罕布什尔大学 (University of New Hampshire) 教授、GYPSY 研究专家保罗·哈维 (Paul Harvey) 对此<a href="https://www.unh.edu/news/cj_nr/2010/may/lw17gen-y.cfm" target="_blank" rel="noreferrer">做过研究</a>,发现 Y 世代拥有「不切实际的期望和对负面反馈的强烈抗拒」,以及「膨胀的自我认知」。他说:「对于那些拥有强烈资格感的人来说,一大挫败感的来源就是期望没被满足。他们往往觉得自己应该得到某种程度的尊重和回报,而这与他们的实际能力和努力程度并不相称,于是他们可能就得不到自己所期待的那种尊重和回报。」</p><p>对于那些要雇佣 Y 世代的人,哈维建议在面试时问一个问题:「你觉得自己普遍比同事/同学/等等更优秀吗?如果是,为什么?」他说:「如果候选人对前半部分回答『是』,却答不上来『为什么』,那可能就有资格感问题。因为资格感常常建立在一种毫无根据的优越感和应得感上。他们被灌输了这种想法——可能是童年时期过度热情的自尊心培养练习导致的——觉得自己不知怎的就很特别,但通常拿不出任何真正的理由来支撑这种信念。」</p><p>而由于现实世界还有胆子把实力当成一个因素,毕业几年后的露西发现自己在这儿:</p><p><img src="'+b+'" alt=""></p><p>露西极度的野心,加上因对自身价值有点儿妄想而滋生的傲慢,让她对刚出校门的头几年就抱有巨大的期望。而她的现实与这些期望相比黯然失色,导致她的「现实 - 期望」幸福分数呈现为负值。</p><p>而且情况还会更糟。除了以上这些,GYPSY 还有一个困扰整整一代人的额外难题:</p><h2 id="gypsy-被人嘲弄" tabindex="-1"><strong>GYPSY 被人嘲弄</strong> <a class="header-anchor" href="#gypsy-被人嘲弄" aria-label="Permalink to &quot;**GYPSY 被人嘲弄**&quot;">​</a></h2><p>当然,Lucy 父母的高中或大学同学里,肯定有一些人最后混得比她父母更成功。虽然他们时不时也会通过小道消息听到一些风声,但大多数时候,他们其实并不太清楚太多其他人的职业到底是啥情况。</p><p>而 Lucy 呢,却发现自己无时无刻不被一个现代现象所嘲弄:<a href="https://waitbutwhy.com/2013/07/7-ways-to-be-insufferable-on-facebook.html" target="_blank" rel="noreferrer">Facebook 形象打造</a>。</p><p>社交媒体为 Lucy 创造了一个这样的世界:A) 别人在干什么都摆在明面上,B) 大多数人呈现的都是自己人生的注水版本,C) 最爱在朋友圈刷职业动态的,通常是那些事业(或恋情)最顺风顺水的人,而挣扎中的人往往不会广而告之。这就让 Lucy 产生了一种错觉,以为其他人都过得特别好,只会让她更加痛苦:</p><p><img src="'+f+'" alt=""></p><p>这就是为什么 Lucy 不开心,或者至少感觉有点沮丧和自己不够好。实际上,她的职业开局大概相当不错,但对她自己来说,感觉却极度令人失望。</p><p>以下是我给 Lucy 的建议:</p><p><strong>1) 保持狂野的野心。</strong> 当今世界对一个有野心的人来说,处处都在冒着机会的泡泡,等你去找到那种鲜花盛开、令人满足的成功。具体方向可能还不清楚,但会自己捋顺的——先随便往里跳一个就行。</p><p><strong>2) 别再觉得自己有多特别了。</strong> 事实是,眼下,你并不特别。你只是另一个完全没经验的年轻人,还没啥可拿得出手的东西。你可以通过长时间的努力工作,让自己变得特别。</p><h2 id="_3-别理其他人。-别人家的草坪看着更绿-这不是什么新鲜概念了-但在今天这个形象打造的世界里-别人家的草坪看着简直像一片荣光四射的大草原。真相是-其他人跟你一样犹豫不决、自我怀疑、心烦意乱-只要你自己做自己的事-就永远没理由去羡慕别人。" tabindex="-1"><strong>3) <a href="https://waitbutwhy.com/2014/06/taming-mammoth-let-peoples-opinions-run-life.html" target="_blank" rel="noreferrer">别理其他人</a>。</strong> 别人家的草坪看着更绿,这不是什么新鲜概念了,但在今天这个形象打造的世界里,别人家的草坪看着简直像一片荣光四射的大草原。真相是,其他人跟你一样犹豫不决、自我怀疑、心烦意乱,只要你自己做自己的事,就永远没理由去羡慕别人。 <a class="header-anchor" href="#_3-别理其他人。-别人家的草坪看着更绿-这不是什么新鲜概念了-但在今天这个形象打造的世界里-别人家的草坪看着简直像一片荣光四射的大草原。真相是-其他人跟你一样犹豫不决、自我怀疑、心烦意乱-只要你自己做自己的事-就永远没理由去羡慕别人。" aria-label="Permalink to &quot;**3) [别理其他人](https://waitbutwhy.com/2014/06/taming-mammoth-let-peoples-opinions-run-life.html)。** 别人家的草坪看着更绿,这不是什么新鲜概念了,但在今天这个形象打造的世界里,别人家的草坪看着简直像一片荣光四射的大草原。真相是,其他人跟你一样犹豫不决、自我怀疑、心烦意乱,只要你自己做自己的事,就永远没理由去羡慕别人。&quot;">​</a></h2><p>如果你喜欢 Wait But Why,请注册我们的 <strong><a href="https://newsletter.waitbutwhy.com/join" target="_blank" rel="noreferrer">邮件列表</a></strong>,新文章发布时我们会发给你。</p><h2 id="想支持-wait-but-why-请访问我们的-patreon-页面。" tabindex="-1">想支持 Wait But Why,请访问我们的 <strong><a href="https://patreon.com/waitbutwhy" target="_blank" rel="noreferrer">Patreon 页面</a></strong>。 <a class="header-anchor" href="#想支持-wait-but-why-请访问我们的-patreon-页面。" aria-label="Permalink to &quot;想支持 Wait But Why,请访问我们的 **[Patreon 页面](https://patreon.com/waitbutwhy)**。&quot;">​</a></h2><p><strong>如果你喜欢这篇,可以看看:</strong></p><p><a href="https://waitbutwhy.com/2013/10/why-procrastinators-procrastinate.html" target="_blank" rel="noreferrer">为什么拖延症患者会拖延</a><br><a href="https://waitbutwhy.com/2014/02/pick-life-partner.html" target="_blank" rel="noreferrer">如何挑选你的人生伴侣</a><br><a href="https://waitbutwhy.com/2013/07/7-ways-to-be-insufferable-on-facebook.html" target="_blank" rel="noreferrer">在 Facebook 上让人无法忍受的 7 种方式</a></p><p><a href="https://twitter.com/share" target="_blank" rel="noreferrer">Tweet</a></p><p><a href="//www.pinterest.com/pin/create/button/?url=https://waitbutwhy.com/2013/09/why-generation-y-yuppies-are-unhappy.html&amp;description=Why%20Generation%20Y%20Yuppies%20Are%20Unhappy" target="_blank" rel="noreferrer"><img src="'+P+'" alt=""></a></p>',69)])])}const U=p(d,[["render",G]]);export{A as __pageData,U as default};
